        /// <param name="worksheet"></param> 
        public void SetDrawToSheet(ExcelWorksheet worksheet)
        {
            var bytes = Convert.FromBase64String(ImgBase64);
            MemoryStream stream = new MemoryStream(bytes);
            var image = Image.FromStream(stream);
            var graphUnit = GraphicsUnit.Pixel;

            #region log

            Console.WriteLine("------------------------------");
            Console.WriteLine("图片准备添加");
            Console.WriteLine(ImgName);
            Console.WriteLine("图片宽高：" + image.Width.ToString() + "," + image.Height.ToString());
            Console.WriteLine("Bounds：" + image.GetBounds(ref graphUnit).ToString());
            Console.WriteLine("物理Dimension：" + image.PhysicalDimension.ToString());
            Console.WriteLine("开始位置：" + StartRow + "," + StartCol);
            Console.WriteLine("结束位置：" + EndRow + "," + EndCol);
            Console.WriteLine("开始偏差：" + (StartRowOffset * 9525) + "," + (StartColOffset * 9525));
            Console.WriteLine("结束偏差：" + (EndRowOffset * 9525) + "," + (EndColOffset * 9525));
            Console.WriteLine("工作簿范围：" + worksheet.Dimension.Address);
             
            #endregion log

            try
            {
                var picture = worksheet.Drawings.AddPicture(ImgName, image);
                Console.WriteLine("图片已添加");

                picture.From.Row = StartRow;
                picture.From.Column = StartCol;
                picture.From.RowOff = StartRowOffset * 9525;
                picture.From.ColumnOff = StartColOffset * 9525;

                picture.To.Row = EndRow;
                picture.To.Column = EndCol;
                picture.To.RowOff = EndRowOffset * 9525;
                picture.To.ColumnOff = EndColOffset * 9525;
            }
            catch (Exception ex)
