        /// <summary>
        /// 读取worksheet上的图
        /// </summary>
        /// <param name="worksheet"></param>
        /// <returns></returns>
        public static List<CellDraw> ReadPictures(ExcelWorksheet worksheet)
        {
            var draws = worksheet.Drawings.ToList();

            var pictures = new List<CellDraw>();

            foreach (var item in draws)
            {
                var draw = new CellDraw();
                draw.StartRow = item.From.Row;
                draw.StartCol = item.From.Column;
                draw.StartRowOffset = item.From.RowOff / 9525;
                draw.StartColOffset = item.From.ColumnOff / 9525;

                draw.EndRow = item.To.Row;
                draw.EndCol = item.To.Column;
                draw.EndRowOffset = item.To.RowOff / 9525;
                draw.EndColOffset = item.To.ColumnOff / 9525;

                var pic = item as ExcelPicture;

                if (pic != null)
                {
                    //draw.WidthPX = pic.Image.Width;
                    //draw.HeightPX = pic.Image.Height;

                    var ms = new MemoryStream();
                    pic.Image.Save(ms, pic.ImageFormat);
                    byte[] arr = new byte[ms.Length];
                    ms.Position = 0;
                    ms.Read(arr, 0, (int)ms.Length);
                    ms.Close();
                    var content = Convert.ToBase64String(arr);
                    draw.ImgBase64 = content;
                }

                draw.ImgName = item.Name;

                pictures.Add(draw);
            }
            return pictures;
        }

